parameters.jsCode:
// Parse the captions JSON and fan out to one item per platform with the
// account id and that network's peak posting hour (today).
const c = JSON.parse($input.first().json.choices[0].message.content);

// >>> Set your Posta social account ids and peak hours here <<<
const ACCOUNTS = { linkedin: 'REPLACE_LINKEDIN_ID', bluesky: 'REPLACE_BLUESKY_ID', threads: 'REPLACE_THREADS_ID' };
const HOURS = { linkedin: 9, bluesky: 12, threads: 18 };

return ['linkedin', 'bluesky', 'threads'].map((p) => ({
  json: {
    platform: p,
    socialAccountIds: ACCOUNTS[p],
    caption: c[p],
    scheduledAt: $now.set({ hour: HOURS[p], minute: 0, second: 0, millisecond: 0 }).toISO(),
  },
}));
